from pyrqa.time_series import TimeSeriesfrom pyrqa.settings import Settingsfrom pyrqa.computing_type import ComputingTypefrom pyrqa.neighbourhood import FixedRadiusfrom pyrqa.metric import EuclideanMetricfrom pyrqa.computation import RPComputation, RQAComputationfrom pyrqa.opencl import OpenCLimport pandas as pdimport timeopencl = OpenCL(platform_id=0, device_ids=(0,))eIMFs = pd.read_csv('ensemble_data_S1_out.csv', index_col=0, header=0)rqa_paras = pd.read_csv('ensemble_data_rqa_paras_S1_out.csv', index_col=None, header=None)det = []e_start_time = time.time()for i in range(0,2):    IMF = eIMFs.iloc[:,i].values    print(IMF)    embedding_dimension = rqa_paras.iloc[i, 0]    time_delay = rqa_paras.iloc[i, 1]    neighbourhood = rqa_paras.iloc[i, 2]    time_series = TimeSeries(IMF,                             embedding_dimension=embedding_dimension,                             time_delay=time_delay)    settings = Settings(time_series,                        computing_type=ComputingType.Classic,                        neighbourhood=FixedRadius(neighbourhood),                        similarity_measure=EuclideanMetric,                        theiler_corrector=0)    computation = RQAComputation.create(settings,                                        verbose=True,                                        opencl=opencl)    result = computation.run()    print(result.determinism)e_end_time = time.time()e_time = e_end_time - e_start_timeprint("+================================================")print('Ensemble time: %s' % e_time)